113	    @Post(consumes = MediaType.APPLICATION_YAML)
114	    @Operation(tags = { "Dashboards" }, summary = "Create a dashboard from yaml source")
115	    public HttpResponse<DashboardResponse> createDashboard(
116	        @RequestBody(description = "The dashboard definition as YAML") @Body String dashboard) throws ConstraintViolationException {
117	        Dashboard dashboardParsed = parseDashboard(dashboard);
118	
119	        if (dashboardParsed.getId() == null) {
120	            throw new IllegalArgumentException("Dashboard id is mandatory");
121	        }
122	        modelValidator.validate(dashboardParsed);
123	
124	        Optional<Dashboard> existingDashboard = dashboardRepository.get(tenantService.resolveTenant(), dashboardParsed.getId());
125	        if (existingDashboard.isPresent()) {
126	            throw new ConstraintViolationException(
127	                Collections.singleton(
128	                    ManualConstraintViolation.of(
129	                        "Dashboard id already exists",
130	                        dashboardParsed,
131	                        Dashboard.class,
132	                        "dashboard.id",
133	                        dashboardParsed.getId()
134	                    )
135	                )
136	            );
137	        }
138	
139	        return HttpResponse.ok(new DashboardResponse(this.save(null, dashboardParsed, dashboard)));
140	    }
