220	    private void removeDefaultDashboardReferences(String dashboardId) {
221	        settingRepository.findByKey(OSS_DASHBOARD_SETTINGS)
222	            .map(Setting::getValue)
223	            .map(value -> JacksonMapper.ofJson(false).convertValue(value, DashboardSettings.class))
224	            .ifPresent(settings ->
225	            {
226	                var builder = settings.toBuilder();
227	
228	                if (dashboardId.equals(settings.getDefaultHomeDashboard())) {
229	                    builder.defaultHomeDashboard(null);
230	                }
231	                if (dashboardId.equals(settings.getDefaultFlowOverviewDashboard())) {
232	                    builder.defaultFlowOverviewDashboard(null);
233	                }
234	                if (dashboardId.equals(settings.getDefaultNamespaceOverviewDashboard())) {
235	                    builder.defaultNamespaceOverviewDashboard(null);
236	                }
237	
238	                DashboardSettings updated = builder.build();
239	                if (updated.equals(settings)) {
240	                    return;
241	                }
242	
243	                settingRepository.save(
244	                    Setting.builder()
245	                        .key(OSS_DASHBOARD_SETTINGS)
246	                        .value(updated)
247	                        .build()
248	                );
249	            });
250	    }
