496	    @Getter
497	    public static class DashboardResponse {
498	        @jakarta.validation.constraints.Pattern(regexp = "^[a-z0-9][a-z0-9_-]*")
499	        private final String tenantId;
500	        @NotNull
501	        @NotBlank
502	        private final String id;
503	        @NotNull
504	        @NotBlank
505	        private final String title;
506	        private final String description;
507	        private final TimeWindow timeWindow;
508	        private final List<Chart<?>> charts;
509	        @NotNull
510	        private final boolean deleted;
511	        private final Instant created;
512	        private final Instant updated;
513	        private final String sourceCode;
514	
515	        public DashboardResponse(Dashboard dashboard) {
516	            this.tenantId = dashboard.getTenantId();
517	            this.id = dashboard.getId();
518	            this.title = dashboard.getTitle();
519	            this.description = dashboard.getDescription();
520	            this.timeWindow = dashboard.getTimeWindow();
521	            this.charts = dashboard.getCharts();
522	            this.deleted = dashboard.isDeleted();
523	            this.created = dashboard.getCreated();
524	            this.updated = dashboard.getUpdated();
525	            this.sourceCode = dashboard.getSourceCode();
526	        }
